const express = require('express');
const router = express.Router();
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const { db } = require('../db');

const SECRET = process.env.JWT_SECRET;

router.post('/register', async (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.status(400).json({ error: 'username/password required' });
  const hash = await bcrypt.hash(password, 10);
  const stmt = db.prepare('INSERT INTO users (username, password_hash) VALUES (?, ?)');
  stmt.run(username, hash, function (err) {
    if (err) {
      if (err.message.includes('UNIQUE')) return res.status(409).json({ error: 'username taken' });
      return res.status(500).json({ error: 'db error' });
    }
    const token = jwt.sign({ id: this.lastID, username }, SECRET, { expiresIn: '7d' });
    res.json({ token, user: { id: this.lastID, username } });
  });
});

router.post('/login', (req, res) => {
  const { username, password } = req.body;
  db.get('SELECT id, username, password_hash FROM users WHERE username = ?', [username], async (err, row) => {
    if (err) return res.status(500).json({ error: 'db error' });
    if (!row) return res.status(401).json({ error: 'invalid credentials' });
    const ok = await bcrypt.compare(password, row.password_hash);
    if (!ok) return res.status(401).json({ error: 'invalid credentials' });
    const token = jwt.sign({ id: row.id, username: row.username }, SECRET, { expiresIn: '7d' });
    res.json({ token, user: { id: row.id, username: row.username } });
  });
});

module.exports = router;

