const express = require('express');
const router = express.Router();
const auth = require('../middleware/auth');
const { db } = require('../db');

// helper to emit events via req.io (attached in index.js)
function emit(req, event, payload) {
  if (req.io) req.io.emit(event, payload);
}

// list tasks for current user
router.get('/', auth, (req, res) => {
  const userId = req.user.id;
  db.all('SELECT * FROM tasks WHERE user_id = ? ORDER BY created_at DESC', [userId], (err, rows) => {
    if (err) return res.status(500).json({ error: 'db error' });
    res.json(rows);
  });
});

// create
router.post('/', auth, (req, res) => {
  const { title, description, status, due_date } = req.body;
  const user_id = req.user.id;
  const stmt = db.prepare('INSERT INTO tasks (title, description, status, due_date, user_id) VALUES (?, ?, ?, ?, ?)');
  stmt.run(title, description, status || 'todo', due_date || null, user_id, function (err) {
    if (err) return res.status(500).json({ error: 'db error' });
    db.get('SELECT * FROM tasks WHERE id = ?', [this.lastID], (err2, row) => {
      emit(req, 'task_created', row);
      res.status(201).json(row);
    });
  });
});

// get single
router.get('/:id', auth, (req, res) => {
  const id = req.params.id;
  const user_id = req.user.id;
  db.get('SELECT * FROM tasks WHERE id = ? AND user_id = ?', [id, user_id], (err, row) => {
    if (err) return res.status(500).json({ error: 'db error' });
    if (!row) return res.status(404).json({ error: 'not found' });
    res.json(row);
  });
});

// update
router.put('/:id', auth, (req, res) => {
  const id = req.params.id;
  const user_id = req.user.id;
  const { title, description, status, due_date } = req.body;
  const stmt = db.prepare(
    `UPDATE tasks SET title = ?, description = ?, status = ?, due_date = ?, updated_at = CURRENT_TIMESTAMP
     WHERE id = ? AND user_id = ?`
  );
  stmt.run(title, description, status, due_date, id, user_id, function (err) {
    if (err) return res.status(500).json({ error: 'db error' });
    if (this.changes === 0) return res.status(404).json({ error: 'not found' });
    db.get('SELECT * FROM tasks WHERE id = ?', [id], (err2, row) => {
      emit(req, 'task_updated', row);
      res.json(row);
    });
  });
});

// delete
router.delete('/:id', auth, (req, res) => {
  const id = req.params.id;
  const user_id = req.user.id;
  db.get('SELECT * FROM tasks WHERE id = ? AND user_id = ?', [id, user_id], (err, row) => {
    if (err) return res.status(500).json({ error: 'db error' });
    if (!row) return res.status(404).json({ error: 'not found' });
    db.run('DELETE FROM tasks WHERE id = ? AND user_id = ?', [id, user_id], function (err2) {
      if (err2) return res.status(500).json({ error: 'db error' });
      emit(req, 'task_deleted', { id: Number(id) });
      res.json({ success: true });
    });
  });
});

module.exports = router;

